    const codeOptions = [
    { grpCd : "CO012", compID : "acb_unit" },
    ];
    $c.data.setCommonCode(codeOptions);
};

scwin.onUdcCompleted = function() {

	// $c.gus.cfDisableKey();
	// scwin.f_SearchHeaderCreate();
    $c.gus.cfDisableKey();
	scwin.f_FieldClear();
   // scwin.f_Setting();
    // lc_acctDeptCls.index = 0;
