//-------------------------------------------------------------------------
// Object 값 반환함수
//-------------------------------------------------------------------------
scwin.f_GetObjValue = function(inObj) {
    return (inObj._wTagName == "OBJECT") ? inObj.getValue().trim() : inObj.getValue().trim();
}

//-------------------------------------------------------------------------
// Object 값 설정함수
//-------------------------------------------------------------------------
scwin.f_SetObjValue = function(inObj, val) {
    if (inObj._wTagName == "OBJECT")
        inObj.setValue(val);
    else
        inObj.setValue(val);
}
